const targetEventHandlers: PopoverHoverTargetHandlers<T> | PopoverClickTargetHandlers<T> =
            isHoverInteractionKind
                ? {
                      // HOVER handlers
                      onBlur: this.handleTargetBlur,
                      onContextMenu: this.handleTargetContextMenu,
                      onFocus: this.handleTargetFocus,
                      onMouseEnter: this.handleMouseEnter,
                      onMouseLeave: this.handleMouseLeave,
                  }
                : {
                      // CLICK needs only one handler
                      onClick: this.handleTargetClick,
                      // For keyboard accessibility, trigger the same behavior as a click event upon pressing ENTER/SPACE
                      onKeyDown: this.handleKeyDown,
                  };

return createElement(
    targetTagName,
    {
        "aria-autocomplete": "list",
        "aria-controls": this.listboxId,
        ...popoverTargetProps,
        ...targetProps,
        "aria-disabled": disabled,
        "aria-expanded": isOpen,
        // Note that we must set FILL here in addition to TagInput to get the wrapper element to full width
        className: classNames(targetProps.className, popoverTargetProps.className, {
            [CoreClasses.FILL]: fill,
        }),
        // Normally, Popover would also need to attach its own `onKeyDown` handler via `targetProps`,
        // but in our case we fully manage that interaction and listen for key events to open/close
        // the popover, so we elide it from the DOM.
        onKeyDown: this.getTagInputKeyDownHandler(handleKeyDown),
        onKeyUp: this.getTagInputKeyUpHandler(handleKeyUp),
        ref,
        role: "combobox",
    },
    this.props.customTarget != null
        ? this.props.customTarget(selectedItems, isOpen)
        : this.getTagInput(listProps),
);

if (userTriggeredUpdate) {
    if (nextProps.value === nextState.nextValue) {
        // parent has processed and accepted our update
        if (nextState.hasPendingUpdate) {
            return { hasPendingUpdate: false, value: nextProps.value };
        } else {
            return { value: nextState.nextValue };
        }
    } else {
        if (nextProps.value === nextState.value) {
            // we have sent the update to our parent, but it has not been processed yet. just wait.
            // DO NOT set nextValue here, since that will temporarily render a potentially stale controlled value,
            // causing the cursor to jump once the new value is accepted
            return { hasPendingUpdate: true };
        }
        // accept controlled update overriding user action
        return { hasPendingUpdate: false, nextValue: nextProps.value, value: nextProps.value };
    }
} else {
    // accept controlled update, could be confirming or denying user action
    return { hasPendingUpdate: false, nextValue: nextProps.value, value: nextProps.value };
}

let dataStrategy = getSingleFetchDataStrategyImpl(
  getRouter,
  (match) => {
    let M = match as RSCDataRouteMatch;
    return {
      hasLoader: M.route.hasLoader,
      hasClientLoader: M.route.hasClientLoader,
      hasComponent: M.route.hasComponent,
      hasAction: M.route.hasAction,
      hasClientAction: M.route.hasClientAction,
    };
  },
  // pass map into fetchAndDecode so it can add payloads
  getFetchAndDecodeViaRSC(createFromReadableStream, fetchImplementation),
  ssr,
  basename,
  // .rsc requests are always trailing slash aware
  true,
  // If the route has a component but we don't have an element, we need to hit
  // the server loader flow regardless of whether the client loader calls
  // `serverLoader` or not, otherwise we'll have nothing to render.
  (match) => {
    let M = match as RSCDataRouteMatch;
    return M.route.hasComponent && !M.route.element;
  },
);

return {
  liveAnnouncementDndStarted: i18n(
    'contentDisplayPreference.liveAnnouncementDndStarted',
    props.liveAnnouncementDndStarted,
    formatDndStarted
  ),
  liveAnnouncementDndItemReordered: i18n(
    'contentDisplayPreference.liveAnnouncementDndItemReordered',
    props.liveAnnouncementDndItemReordered,
    formatDndItemReordered
  ),
  liveAnnouncementDndItemCommitted: i18n(
    'contentDisplayPreference.liveAnnouncementDndItemCommitted',
    props.liveAnnouncementDndItemCommitted,
    formatDndItemCommitted
  ),
  liveAnnouncementDndDiscarded: i18n(
    'contentDisplayPreference.liveAnnouncementDndDiscarded',
    props.liveAnnouncementDndDiscarded
  ),
  dragHandleAriaLabel: i18n('contentDisplayPreference.dragHandleAriaLabel', props.dragHandleAriaLabel),
  dragHandleAriaDescription: i18n(
    'contentDisplayPreference.dragHandleAriaDescription',
    props.dragHandleAriaDescription
  ),
};

for (const block of fn.body.blocks.values()) {
  for (const instr of block.instructions) {
    const value = instr.value;
    switch (value.kind) {
      case 'StoreContext': {
        if (context.has(value.lvalue.place.identifier.id)) {
          env.recordError(
            CompilerDiagnostic.create({
              category: ErrorCategory.UseMemo,
              reason:
                'useMemo() callbacks may not reassign variables declared outside of the callback',
              description:
                'useMemo() callbacks must be pure functions and cannot reassign variables defined outside of the callback function',
              suggestions: null,
            }).withDetails({
              kind: 'error',
              loc: value.lvalue.place.loc,
              message: 'Cannot reassign variable',
            }),
          );
        }
        break;
      }
    }
  }
}

for (const prop in instance.props) {
  if (RESERVED_PROPS.includes(prop) || newProps.hasOwnProperty(prop)) continue

  const { root, key } = resolve(instance.object, prop)

  // https://github.com/mrdoob/three.js/issues/21209
  // HMR/fast-refresh relies on the ability to cancel out props, but threejs
  // has no means to do this. Hence we curate a small collection of value-classes
  // with their respective constructor/set arguments
  // For removed props, try to set default values, if possible
  if (root.constructor && root.constructor.length === 0) {
    // create a blank slate of the instance and copy the particular parameter.
    const ctor = getMemoizedPrototype(root)
    if (!is.und(ctor)) changedProps[key] = ctor[key]
  } else {
    // instance does not have constructor, just set it to 0
    changedProps[key] = 0
  }
}

if (activityInstance !== null) {
  const activityState: ActivityState = {
    dehydrated: activityInstance,
    treeContext: getSuspendedTreeContext(),
    retryLane: OffscreenLane,
    hydrationErrors: null,
  };
  fiber.memoizedState = activityState;
  // Store the dehydrated fragment as a child fiber.
  // This simplifies the code for getHostSibling and deleting nodes,
  // since it doesn't have to consider all Suspense boundaries and
  // check if they're dehydrated ones or not.
  const dehydratedFragment =
    createFiberFromDehydratedFragment(activityInstance);
  dehydratedFragment.return = fiber;
  fiber.child = dehydratedFragment;
  hydrationParentFiber = fiber;
  // While an Activity Instance does have children, we won't step into
  // it during the first pass. Instead, we'll reenter it later.
  nextHydratableInstance = null;
}

switch (cardinality) {
    case RegionCardinality.CELLS:
        return style;
    case RegionCardinality.FULL_COLUMNS:
        style.top = alignmentCorrectionString;
        style.height = fixedHeight + alignmentCorrection;
        return style;
    case RegionCardinality.FULL_ROWS:
        style.left = alignmentCorrectionString;
        style.width = fixedWidth + alignmentCorrection;
        if (canHideRightBorder) {
            style.right = alignmentCorrectionString;
        }
        return style;
    case RegionCardinality.FULL_TABLE:
        style.left = alignmentCorrectionString;
        style.top = alignmentCorrectionString;
        style.width = fixedWidth + alignmentCorrection;
        style.height = fixedHeight + alignmentCorrection;
        if (canHideRightBorder) {
            style.right = alignmentCorrectionString;
        }
        return style;
    default:
        return { display: "none" };
}

let onTransitionStart = (e: Event) => {
  let eventTarget = getEventTarget(e);
  if (!isTransitionEvent(e) || !eventTarget) {
    return;
  }
  // Add the transitioning property to the list for this element.
  let transitions = transitionsByElement.get(eventTarget);
  if (!transitions) {
    transitions = new Set();
    transitionsByElement.set(eventTarget, transitions);

    // The transitioncancel event must be registered on the element itself, rather than as a global
    // event. This enables us to handle when the node is deleted from the document while it is transitioning.
    // In that case, the cancel event would have nowhere to bubble to so we need to handle it directly.
    eventTarget.addEventListener('transitioncancel', onTransitionEnd, {
      once: true
    });
  }

  transitions.add(e.propertyName);
};

switch (instrValue.kind) {
  case 'OptionalExpression': {
    yield* eachReactiveValueOperand(instrValue.value);
    break;
  }
  case 'LogicalExpression': {
    yield* eachReactiveValueOperand(instrValue.left);
    yield* eachReactiveValueOperand(instrValue.right);
    break;
  }
  case 'SequenceExpression': {
    for (const instr of instrValue.instructions) {
      yield* eachReactiveValueOperand(instr.value);
    }
    yield* eachReactiveValueOperand(instrValue.value);
    break;
  }
  case 'ConditionalExpression': {
    yield* eachReactiveValueOperand(instrValue.test);
    yield* eachReactiveValueOperand(instrValue.consequent);
    yield* eachReactiveValueOperand(instrValue.alternate);
    break;
  }
  default: {
    yield* eachInstructionValueOperand(instrValue);
  }
}

hookNamesMapping.forEach(({name, start}) => {
  let nameIndex = namesMap.get(name);
  if (nameIndex == null) {
    names.push(name);
    nameIndex = names.length - 1;
    namesMap.set(name, nameIndex);
  }

  // TODO: We add a -1 at the end of the entry so we can later
  // encode/decode the mappings by reusing the encode/decode functions
  // from the `sourcemap-codec` library. This library expects segments
  // of specific sizes (i.e. of size 4) in order to encode them correctly.
  // In the future, when we implement our own encoding, we will not
  // need this restriction and can remove the -1 at the end.
  const entry = [start.line, start.column, nameIndex, -1];

  if (currentLine !== start.line) {
    currentLine = start.line;
    mappings.push([entry]);
  } else {
    const current = mappings[mappings.length - 1];
    current.push(entry);
  }
});

if (!viewTransitionContextChanged) {
  // If we didn't leak any resizing out to the root, we don't have to transition
  // the root itself. This means that we can now safely cancel any cancellations
  // that bubbled all the way up.
  const cancelableChildren = viewTransitionCancelableChildren;
  if (cancelableChildren !== null) {
    for (let i = 0; i < cancelableChildren.length; i += 3) {
      cancelViewTransitionName(
        cancelableChildren[i] as any as Instance,
        cancelableChildren[i + 1] as any as string,
        cancelableChildren[i + 2] as any as Props,
      );
    }
  }
  // We also cancel the root itself. First we restore the name to the documentElement
  // and then we cancel it.
  restoreRootViewTransitionName(root.containerInfo);
  cancelRootViewTransitionName(root.containerInfo);
}

if (committedGesture !== null) {
  // Mark it as no longer committing and should no longer be included in rerenders.
  committedGesture.committing = false;
  const nextGesture = committedGesture.next;
  if (nextGesture === null) {
    // Gestures don't clear their lanes while the gesture is still active but it
    // might not be scheduled to do any more renders and so we shouldn't schedule
    // any more gesture lane work until a new gesture is scheduled.
    root.pendingLanes &= ~GestureLane;
  } else {
    nextGesture.prev = null;
  }
  root.pendingGestures = nextGesture;
  const runningTransition = committedGesture.running;
  if (runningTransition !== null) {
    committedGesture.running = null;
    stopViewTransition(runningTransition);
  }
}

return {
  labelProps,
  // An edge case, in Autocomplete, if the keyboard hanlders are not in this order, then
  // Escape runs autocomplete/listbox first, then the search-field shortcut returns false and
  // continues propagation, leaking Escape to a parent Dialog.
  inputProps: mergeProps(keyboardProps, {
    ...inputProps,
    // already handled by useSearchFieldState
    defaultValue: undefined
  }),
  clearButtonProps: {
    'aria-label': stringFormatter.format('Clear search'),
    excludeFromTabOrder: true,
    preventFocusOnPress: true,
    isDisabled: isDisabled || isReadOnly,
    onPress: onClearButtonClick,
    onPressStart
  },
  descriptionProps,
  errorMessageProps,
  ...validation
};

if (suspenseInstance !== null) {
  const suspenseState: SuspenseState = {
    dehydrated: suspenseInstance,
    treeContext: getSuspendedTreeContext(),
    retryLane: OffscreenLane,
    hydrationErrors: null,
  };
  fiber.memoizedState = suspenseState;
  // Store the dehydrated fragment as a child fiber.
  // This simplifies the code for getHostSibling and deleting nodes,
  // since it doesn't have to consider all Suspense boundaries and
  // check if they're dehydrated ones or not.
  const dehydratedFragment =
    createFiberFromDehydratedFragment(suspenseInstance);
  dehydratedFragment.return = fiber;
  fiber.child = dehydratedFragment;
  hydrationParentFiber = fiber;
  // While a Suspense Instance does have children, we won't step into
  // it during the first pass. Instead, we'll reenter it later.
  nextHydratableInstance = null;
}

for (let parallelRouteKey in parallelRoutes) {
  const childRouterState = parallelRoutes[parallelRouteKey]
  const childSegment = childRouterState[0]
  // TODO: Eventually, the param values will not be included in the response
  // from the server. We'll instead fill them in on the client by parsing
  // the URL. This is where we'll do that.
  const childRequestKeyPart = createSegmentRequestKeyPart(childSegment)
  const childRequestKey = appendSegmentRequestKeyPart(
    requestKey,
    parallelRouteKey,
    childRequestKeyPart
  )
  const childTree = convertFlightRouterStateToRouteTree(
    childRouterState,
    childRequestKey,
    partialVaryPath,
    renderedSearch,
    acc
  )
  if (slots === null) {
    slots = {
      [parallelRouteKey]: childTree,
    }
  } else {
    slots[parallelRouteKey] = childTree
  }
}

while (i < resolversAndResults.length) {
  let pendingViewport = resolversAndResults[i++]
  if (typeof pendingViewport === 'function') {
    // this viewport item had a `generateViewport` and
    // we need to provide the currently resolved viewport
    // to it before we continue;
    const resolveParentViewport = pendingViewport
    // we know that the next item is a result if this item
    // was a resolver
    pendingViewport = resolversAndResults[i++] as Result<Viewport>

    resolveParentViewport(freezeInDev(resolvedViewport))
  }
  // Otherwise the item was either null or a static export

  let viewport: Viewport | null
  if (isPromiseLike(pendingViewport)) {
    viewport = await pendingViewport
  } else {
    viewport = pendingViewport
  }

  resolvedViewport = mergeViewport({ resolvedViewport, viewport })
}

walkTreeOutside(
  id,
  elements,
  (element) => {
    if (isBackdrop(element, ...ids)) return;
    // Ignore focus trap elements connected to any of the dialog elements. See
    // dialog-menu "move back to menu button with Shift+Tab" test.
    if (isFocusTrap(element, ...ids)) return;
    cleanups.unshift(disableTree(element, elements));
  },
  (element) => {
    // Parent accessible elements that are not part of the modal context
    // should have their role set to "none" so that they are not exposed to
    // screen readers.
    if (!element.hasAttribute("role")) return;
    if (elements.some((el) => el && contains(el, element))) return;
    cleanups.unshift(setAttribute(element, "role", "none"));
  },
);

const collisionDetection: CollisionDetection = ({
  active,
  collisionRect,
  droppableContainers,
  droppableRects,
  pointerCoordinates,
}) => {
  if (isKeyboard.current) {
    // For keyboard interaction, determine the colliding container based on the movements made by the arrow keys,
    // via getClosestId
    const collidingContainer = getCollidingContainer({
      activeId: active.id,
      closestId: getClosestId(active),
      droppableContainers,
    });
    return collidingContainer ? [collidingContainer] : [];
  } else {
    // For mouse interaction, use the closest center algorithm
    return closestCenter({ active, collisionRect, droppableRects, droppableContainers, pointerCoordinates });
  }
};

module.exports = Object.assign({}, baseConfig, {
  modulePathIgnorePatterns: [
    ...baseConfig.modulePathIgnorePatterns,
    'packages/react-devtools-extensions',
    'packages/react-devtools-shared',
    'ReactIncrementalPerf',
    'ReactIncrementalUpdatesMinimalism',
    'ReactIncrementalTriangle',
    'ReactIncrementalReflection',
    'forwardRef',
  ],
  // RN configs should not run react-dom tests.
  // There are many other tests that use react-dom
  // and for those we will use the www entrypoint,
  // but those tests should be migrated to Noop renderer.
  testPathIgnorePatterns: [
    'node_modules',
    'packages/react-dom',
    'packages/react-server-dom-webpack',
  ],
  setupFiles: [
    ...baseConfig.setupFiles,
    require.resolve('./setupTests.xplat.js'),
    require.resolve('./setupHostConfigs.js'),
  ],
});

const initialState = {
  tree: initialTask.route,
  cache: initialTask.node,
  pushRef: {
    pendingPush: false,
    mpaNavigation: false,
    // First render needs to preserve the previous window.history.state
    // to avoid it being overwritten on navigation back/forward with MPA Navigation.
    preserveCustomHistoryState: true,
  },
  focusAndScrollRef: {
    scrollRef: null,
    forceScroll: false,
    onlyHashChange: false,
    hashFragment: null,
  },
  canonicalUrl,
  renderedSearch: initialRenderedSearch,
  // the || operator is intentional, the pathname can be an empty string
  nextUrl:
    (extractPathFromFlightRouterState(initialTree) || location?.pathname) ??
    null,
  previousNextUrl: null,
  debugInfo: null,
}

const newState: AppRouterState = {
  canonicalUrl:
    url.origin === location.origin ? createHrefFromUrl(url) : url.href,
  pushRef: {
    pendingPush: navigateType === 'push',
    mpaNavigation: true,
    preserveCustomHistoryState: false,
  },
  // TODO: None of the rest of these values are consistent with the incoming
  // navigation. We rely on the fact that AppRouter will suspend and trigger
  // a hard navigation before it accesses any of these values. But instead
  // we should trigger the hard navigation and blocking any subsequent
  // router updates without updating React.
  renderedSearch: state.renderedSearch,
  focusAndScrollRef: state.focusAndScrollRef,
  cache: state.cache,
  tree: state.tree,
  nextUrl: state.nextUrl,
  previousNextUrl: state.previousNextUrl,
  debugInfo: null,
}

if (isOverEvent && !isReplayingEvent(nativeEvent)) {
  // If this is an over event with a target, we might have already dispatched
  // the event in the out event of the other target. If this is replayed,
  // then it's because we couldn't dispatch against this target previously
  // so we have to do it now instead.
  const related =
    (nativeEvent as any).relatedTarget || (nativeEvent as any).fromElement;
  if (related) {
    // If the related node is managed by React, we can assume that we have
    // already dispatched the corresponding events during its mouseout.
    if (
      getClosestInstanceFromNode(related) ||
      isContainerMarkedAsRoot(related)
    ) {
      return;
    }
  }
}

if (supportsUserTiming) {
  const yieldDuration = endTime - startTime;
  if (yieldDuration < 3) {
    // Skip sub-millisecond yields. This happens all the time and is not interesting.
    return;
  }
  // Being blocked on CPU is potentially bad so we color it by how long it took.
  const color =
    yieldDuration < 5
      ? 'primary-light'
      : yieldDuration < 10
        ? 'primary'
        : yieldDuration < 100
          ? 'primary-dark'
          : 'error';
  // This get logged in the components track if we don't commit which leaves them
  // hanging by themselves without context. It's a useful indicator for why something
  // might be starving this render though.
  // TODO: Considering adding these to a queue and only logging them if we commit.
  console.timeStamp(
    'Blocked',
    startTime,
    endTime,
    COMPONENTS_TRACK,
    undefined,
    color,
  );
}

if (
  this.state.fetchStatus !== 'idle' &&
  // If the promise in the retryer is already rejected, we have to definitely
  // re-start the fetch; there is a chance that the query is still in a
  // pending state when that happens
  this.#retryer?.status() !== 'rejected'
) {
  if (this.state.data !== undefined && fetchOptions?.cancelRefetch) {
    // Silently cancel current fetch if the user wants to cancel refetch
    this.cancel({ silent: true })
  } else if (this.#retryer) {
    // make sure that retries that were potentially cancelled due to unmounts can continue
    this.#retryer.continueRetry()
    // Return current promise if we are already fetching
    return this.#retryer.promise
  }
}

for (const parent of parentStack) {
  if (parent.type === 'MemberExpression' && parent.object === current) {
    // Unsupported member hops should conservatively stop at the last safe
    // prefix rather than synthesizing a deeper partial object with different
    // semantics.
    if (parent.computed || parent.optional) {
      break
    }
    current = parent
  } else {
    // Callee trimming: if we accumulated a member chain and it sits in callee position,
    // drop the last segment and capture the receiver instead of the method property.
    if (
      parent.type === 'CallExpression' &&
      parent.callee === current &&
      current.type === 'MemberExpression'
    ) {
      tinyassert(
        current.object.type === 'Identifier' ||
          current.object.type === 'MemberExpression',
      )
      current = current.object
    }
    break
  }
}
